CREATE TABLE `rcptable` (
  `rcpID` varchar(20) DEFAULT NULL,
  `accID` varchar(20) NOT NULL,
  `rcpDetails` text,
  `rcpIngred` text,
  `rcpSteps` text,
  `imgID` varchar(20) DEFAULT NULL,
  `rcpGenre` varchar(100) DEFAULT NULL,
  `rcpDesc` text,
  `rcpAmount` varchar(200) DEFAULT NULL,
  UNIQUE KEY `rcpID` (`rcpID`),
  KEY `fk_rcp_acc` (`accID`),
  KEY `fk_rcp_img` (`imgID`),
  CONSTRAINT `fk_rcp_acc` FOREIGN KEY (`accID`) REFERENCES `acctable` (`accID`),
  CONSTRAINT `fk_rcp_img` FOREIGN KEY (`imgID`) REFERENCES `imgtable` (`imgID`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
