/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `before_rcp_insert` BEFORE INSERT ON `rcptable` FOR EACH ROW BEGIN
    DECLARE max_num INT;

    -- Get the numeric part of the current max accID
    SELECT IFNULL(MAX(CAST(SUBSTRING(rcpID,5) AS UNSIGNED)), 0)
    INTO max_num
    FROM rcpTable;

    -- Assign NEW.accID as 'acc-' + zero-padded number
    SET NEW.rcpID = CONCAT('rcp-', LPAD(max_num + 1, 3, '0'));
END */;;
